const KEY = "zen-code-reader";
const DEFAULT_WPM = 120;
const MIN_SAMPLE_MS = 500;
const MAX_SAMPLE_MS = 10 * 60 * 1000;
const app = document.getElementById("app");
const toast = document.getElementById("toast");

let state = load() || { chunks: [], i: 0, totalWords: 0, totalMs: 0 };
if (typeof state.totalWords !== "number") state.totalWords = 0;
if (typeof state.totalMs !== "number") state.totalMs = 0;

let chunkStart = 0;
let showFinishTime = false;

function render() {
  if (state.chunks.length) renderReader();
  else renderPaste();
}

function renderPaste() {
  app.innerHTML = `
    <div class="paste">
      <textarea id="ta" placeholder='paste reading plan JSON — [{ "title": "...", "language": "js", "code": "..." }, ...]' spellcheck="false"></textarea>
      <div class="error" id="err"></div>
      <div class="row">
        <button class="btn" id="begin">begin</button>
        <label class="btn file-btn">
          upload .json
          <input type="file" id="file" accept=".json,application/json">
        </label>
      </div>
      <details class="howto">
        <summary>how to make a reading plan</summary>
        <p>Paste this prompt into Claude Code (or any AI with access to your repo). It writes the plan to <code>apps/zen-code/plans/</code> so you can upload it here.</p>
        <pre id="prompt-text"></pre>
        <div class="copy-row">
          <button class="linkish" id="copy">copy prompt</button>
        </div>
      </details>
    </div>
  `;

  document.getElementById("prompt-text").textContent = PROMPT;

  const ta = document.getElementById("ta");
  const err = document.getElementById("err");
  const setErr = (m) => { err.textContent = m || ""; };

  document.getElementById("begin").onclick = () => {
    setErr("");
    if (!ta.value.trim()) { setErr("paste a plan first"); return; }
    loadPlanFromText(ta.value, setErr);
  };

  document.getElementById("file").onchange = (e) => {
    setErr("");
    const f = e.target.files && e.target.files[0];
    if (!f) return;
    const reader = new FileReader();
    reader.onload = () => loadPlanFromText(String(reader.result || ""), setErr);
    reader.onerror = () => setErr("could not read file");
    reader.readAsText(f);
  };

  document.getElementById("copy").onclick = copyPrompt;
}

function loadPlanFromText(text, onError) {
  try {
    const chunks = parsePlan(text);
    state = { chunks, i: 0, totalWords: state.totalWords, totalMs: state.totalMs };
    save();
    render();
  } catch (e) {
    onError(e.message || "could not parse plan");
  }
}

function parsePlan(text) {
  const trimmed = text.trim().replace(/^```(?:json)?\s*/i, "").replace(/```\s*$/i, "");
  const data = JSON.parse(trimmed);
  return normalizeChunks(data);
}

function normalizeChunks(input) {
  const arr = Array.isArray(input) ? input : (input && Array.isArray(input.chunks) ? input.chunks : null);
  if (!arr) throw new Error("expected a JSON array of chunks");
  const out = [];
  for (const item of arr) {
    if (!item || typeof item.code !== "string" || !item.code.trim()) continue;
    out.push({
      title: typeof item.title === "string" ? item.title : "",
      language: typeof item.language === "string" ? item.language.toLowerCase() : "",
      code: item.code
    });
  }
  if (!out.length) throw new Error("no chunks with code found");
  return out;
}

function showToast(msg) {
  toast.textContent = msg;
  toast.classList.add("show");
  clearTimeout(showToast._t);
  showToast._t = setTimeout(() => toast.classList.remove("show"), 1600);
}

async function copyPrompt() {
  try {
    await navigator.clipboard.writeText(PROMPT);
    showToast("prompt copied");
  } catch {
    showToast("copy failed — select & copy manually");
  }
}

function renderReader() {
  const { chunks, i } = state;
  const c = chunks[i];
  const atStart = i === 0;
  const atEnd = i === chunks.length - 1;
  const lang = c.language || "none";
  const langClass = c.language ? `language-${escapeHtml(c.language)}` : "";

  app.innerHTML = `
    <button class="reset" id="reset" title="new plan">&times;</button>
    <button class="eta" id="eta" title="tap for finish time">${escapeHtml(etaText())}</button>
    <button class="nav prev" id="prev" ${atStart ? "disabled" : ""} aria-label="previous">&lsaquo;</button>
    <div class="reader-wrap">
      ${c.title ? `<div class="title">${escapeHtml(c.title)}</div>` : ""}
      <div class="code-wrap" id="code-wrap">
        <pre><code class="${langClass}" id="code">${escapeHtml(c.code)}</code></pre>
      </div>
    </div>
    <button class="nav next" id="next" ${atEnd ? "disabled" : ""} aria-label="next">&rsaquo;</button>
    <div class="counter">${i + 1} / ${chunks.length}</div>
  `;

  chunkStart = Date.now();

  if (window.Prism && c.language) {
    try { Prism.highlightElement(document.getElementById("code")); } catch {}
  }

  document.getElementById("prev").onclick = () => go(-1);
  document.getElementById("next").onclick = () => go(1);
  document.getElementById("code-wrap").onclick = (e) => {
    if (window.getSelection && String(window.getSelection()).length > 0) return;
    go(1);
  };
  document.getElementById("reset").onclick = (e) => {
    e.stopPropagation();
    if (confirm("discard current plan?")) reset();
  };
  const eta = document.getElementById("eta");
  eta.onclick = (e) => {
    e.stopPropagation();
    showFinishTime = !showFinishTime;
    eta.textContent = etaText();
  };
}

function go(delta) {
  const n = state.chunks.length;
  if (!n) return;
  const newI = Math.max(0, Math.min(n - 1, state.i + delta));
  if (newI === state.i) return;
  if (delta > 0) sampleCurrentChunk();
  state.i = newI;
  showFinishTime = false;
  save();
  render();
}

function sampleCurrentChunk() {
  if (!chunkStart) return;
  const elapsed = Date.now() - chunkStart;
  chunkStart = 0;
  if (elapsed < MIN_SAMPLE_MS || elapsed > MAX_SAMPLE_MS) return;
  const w = wordCount(state.chunks[state.i] && state.chunks[state.i].code);
  if (!w) return;
  state.totalMs += elapsed;
  state.totalWords += w;
}

function currentWpm() {
  if (state.totalMs > 0 && state.totalWords > 0) {
    return state.totalWords / (state.totalMs / 60000);
  }
  return DEFAULT_WPM;
}

function remainingWords() {
  let sum = 0;
  for (let k = state.i; k < state.chunks.length; k++) {
    sum += wordCount(state.chunks[k].code);
  }
  return sum;
}

function minutesLeft() {
  const wpm = currentWpm();
  if (!wpm) return null;
  return remainingWords() / wpm;
}

function formatMins(m) {
  if (m < 1) return "< 1 min left";
  if (m < 60) return `~${Math.round(m)} min left`;
  const h = Math.floor(m / 60);
  const rem = Math.round(m % 60);
  return rem ? `~${h}h ${rem}m left` : `~${h}h left`;
}

function formatFinish(m) {
  const d = new Date(Date.now() + m * 60000);
  let h = d.getHours();
  const min = String(d.getMinutes()).padStart(2, "0");
  const ampm = h >= 12 ? "pm" : "am";
  h = h % 12 || 12;
  return `done ~${h}:${min}${ampm}`;
}

function etaText() {
  const m = minutesLeft();
  if (m == null || m <= 0) return "";
  return showFinishTime ? formatFinish(m) : formatMins(m);
}

function reset() {
  state = { chunks: [], i: 0, totalWords: state.totalWords, totalMs: state.totalMs };
  chunkStart = 0;
  showFinishTime = false;
  save();
  render();
}

document.addEventListener("keydown", (e) => {
  if (!state.chunks.length) return;
  const tag = (document.activeElement && document.activeElement.tagName) || "";
  if (tag === "TEXTAREA" || tag === "INPUT") return;
  if (e.key === "ArrowRight" || e.key === " ") { e.preventDefault(); go(1); }
  else if (e.key === "ArrowLeft") { e.preventDefault(); go(-1); }
});
